import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Home from './pages/Home';
import RecipeList from './pages/RecipeList';
import RecipeView from './pages/RecipeView';
import PlaceholderPage from './pages/PlaceholderPage';
import Profile from './pages/Profile';
import Planner from './pages/Planner';
import Classes from './pages/Classes';
import Admin from './pages/Admin';
import Shop from './pages/Shop';
import BottomNav from './components/BottomNav';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/recipes" element={<RecipeList />} />
        <Route path="/recipe/:id" element={<RecipeView />} />
        <Route path="/classes" element={<Classes />} />
        <Route path="/planner" element={<Planner />} />
        <Route path="/notifications" element={<PlaceholderPage title="Notifications" />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/admin" element={<Admin />} />
        <Route path="/shop" element={<Shop />} />
      </Routes>
      <BottomNav />
    </BrowserRouter>
  );
}

export default App;

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Home, Compass, PlaySquare, CalendarHeart, User, ShoppingBag } from 'lucide-react';

export default function BottomNav() {
    const navigate = useNavigate();
    const location = useLocation();

    // Do not show bottom nav on recipe specific views, cooking mode, or admin panel
    if (location.pathname.startsWith('/recipe/') || location.pathname.startsWith('/admin')) return null;

    const navItems = [
        { path: '/', icon: Home, label: 'Home' },
        { path: '/recipes', icon: Compass, label: 'Discover' },
        { path: '/classes', icon: PlaySquare, label: 'Classes' },
        { path: '/shop', icon: ShoppingBag, label: 'Shop' },
        { path: '/planner', icon: CalendarHeart, label: 'Planner' },
        { path: '/profile', icon: User, label: 'Profile' },
    ];

    return (
        <div className="fixed bottom-4 md:bottom-8 left-1/2 -translate-x-1/2 w-[calc(100%-2rem)] max-w-[480px] z-50">
            <nav className="bg-[#070B14]/80 backdrop-blur-xl border border-white/10 rounded-2xl p-2 shadow-[0_8px_32px_rgba(0,0,0,0.6),inset_0_1px_1px_rgba(255,255,255,0.1)] flex justify-between items-center relative overflow-hidden">
                {/* Subtle top glare */}
                <div className="absolute top-0 left-0 right-0 h-[1px] bg-gradient-to-r from-transparent via-white/20 to-transparent"></div>

                {navItems.map((item) => {
                    const isActive = location.pathname === item.path;
                    const Icon = item.icon;
                    return (
                        <button
                            key={item.path}
                            onClick={() => navigate(item.path)}
                            className="relative flex flex-col items-center justify-center w-full h-12 rounded-xl transition-all duration-300"
                        >
                            {isActive && (
                                <div className="absolute inset-0 bg-indigo-500/20 rounded-xl shadow-[inset_0_1px_1px_rgba(255,255,255,0.1)] pointer-events-none"></div>
                            )}
                            <Icon 
                                size={20} 
                                className={`mb-1 transition-all duration-300 ${isActive ? 'text-indigo-400 scale-110 drop-shadow-[0_0_8px_rgba(99,102,241,0.8)]' : 'text-slate-400 hover:text-slate-200'}`} 
                            />
                            <span className={`text-[9px] font-bold tracking-wider transition-colors ${isActive ? 'text-indigo-300' : 'text-slate-500'}`}>
                                {item.label}
                            </span>
                        </button>
                    );
                })}
            </nav>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChevronLeft, Bell, ChefHat } from 'lucide-react';

export default function Header({ variant = 'home', title, rightAction, transparentOverride = false }) {
    const navigate = useNavigate();
    const [scrolled, setScrolled] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            const isScrolled = window.scrollY > 20;
            if (isScrolled !== scrolled) {
                setScrolled(isScrolled);
            }
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, [scrolled]);

    // Apply transparent background if not scrolled and no override is forcing transparency
    const bgClass = (scrolled && !transparentOverride)
        ? 'bg-[#070B14]/85 backdrop-blur-xl border-b border-white/5 shadow-[0_4px_24px_rgba(0,0,0,0.4)]'
        : 'bg-transparent border-b border-transparent';

    if (variant === 'home') {
        return (
            <nav className={`fixed top-0 left-0 right-0 z-50 px-4 py-2.5 md:px-6 md:py-3 flex justify-between items-center transition-all duration-300 ${bgClass}`}>
                <div className="flex items-center gap-2.5 cursor-pointer">
                    <img src="/CWC.svg" alt="CWC Logo" className="h-7 md:h-8 w-auto object-contain" onError={(e) => {
                        e.target.style.display = 'none';
                        if (e.target.nextSibling) e.target.nextSibling.style.display = 'flex';
                    }} />
                    {/* Fallback icon in case CWC.svg fails to load */}
                    <div className="hidden w-8 h-8 rounded-lg bg-indigo-500/20 border border-indigo-500/30 items-center justify-center">
                        <ChefHat size={16} className="text-indigo-400" />
                    </div>
                    <span className="text-lg font-bold tracking-tight text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)]">CWC+</span>
                </div>
                <div className="flex items-center gap-3 md:gap-4">
                    <button
                        onClick={() => navigate('/notifications')}
                        className="p-1.5 rounded-full bg-black/40 backdrop-blur-md border border-white/10 hover:bg-white/10 transition-colors relative shadow-[inset_0_1px_1px_rgba(255,255,255,0.1),0_2px_4px_rgba(0,0,0,0.5)]">
                        <Bell size={18} className="text-slate-300 md:w-5 md:h-5" />
                        <span className="absolute top-1 right-1.5 w-1.5 h-1.5 bg-rose-500 rounded-full shadow-[0_0_8px_rgba(244,63,94,0.8)]"></span>
                    </button>
                    <div
                        onClick={() => navigate('/profile')}
                        className="w-8 h-8 md:w-9 md:h-9 rounded-full overflow-hidden border-2 border-white/10 cursor-pointer hover:border-indigo-400 transition-colors shadow-[0_4px_8px_rgba(0,0,0,0.5)] bg-black/40">
                        <img src="https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=100"
                            alt="User Avatar" className="w-full h-full object-cover" />
                    </div>
                </div>
            </nav>
        );
    }

    return (
        <nav className={`fixed top-0 left-0 right-0 z-50 px-4 py-3 md:px-6 md:py-4 flex justify-between items-center transition-all duration-300 ${bgClass}`}>
            <div className="flex items-center gap-3 cursor-pointer group" onClick={() => navigate(-1)}>
                <button className="w-9 h-9 md:w-10 md:h-10 flex items-center justify-center rounded-full bg-black/40 backdrop-blur-md border border-white/10 hover:bg-white/10 transition-colors shadow-[inset_0_1px_1px_rgba(255,255,255,0.1),0_2px_4px_rgba(0,0,0,0.5)]">
                    <ChevronLeft size={20} className="text-slate-300 group-hover:text-white transition-colors group-hover:-translate-x-0.5" />
                </button>
                {title && (
                    <span className="text-lg font-bold tracking-tight text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)]">
                        {title}
                    </span>
                )}
            </div>

            {rightAction && (
                <div className="flex items-center gap-3">
                    {rightAction}
                </div>
            )}
        </nav>
    );
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const initialUsers = [
    { id: '1', name: 'John Doe', email: 'john@example.com', subscriptionTier: 'Free' },
    { id: '2', name: 'Jane Smith', email: 'jane@example.com', subscriptionTier: 'Pro Premium' }
];

export function useAllUsers() {
    const [users, setUsers] = useState([]);

    useEffect(() => {
        const fetchUsers = async () => {
            const { data, error } = await supabase.from('people').select('*').order('created_at', { ascending: false });

            if (error) {
                console.error("Error fetching users:", error);
                const stored = localStorage.getItem('cwc_simulated_users');
                if (stored) setUsers(JSON.parse(stored));
                else setUsers(initialUsers);
                return;
            }

            if (data && data.length > 0) {
                setUsers(data);
            } else {
                setUsers(initialUsers);
            }
        };

        fetchUsers();

        const channel = supabase.channel('people_changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'people' }, payload => {
                fetchUsers();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, []);

    const addUser = async (newUser) => {
        const { data, error } = await supabase.from('people').insert([newUser]).select();
        if (error) {
            console.error("Error adding user:", error);
            setUsers(prev => [...prev, { ...newUser, id: Date.now().toString() }]);
        } else if (data) {
            setUsers(prev => [data[0], ...prev.filter(u => u.id !== data[0].id)]);
        }
    };

    const removeUser = async (id) => {
        const { error } = await supabase.from('people').delete().eq('id', id);
        if (error) console.error("Error deleting user:", error);

        setUsers(prev => prev.filter(u => u.id !== id));
    };

    const updateUserTier = async (id, newTier) => {
        const { error } = await supabase.from('people').update({ subscription_tier: newTier }).eq('id', id);
        if (error) console.error("Error updating user tier:", error);

        setUsers(prev => prev.map(u => u.id === id ? { ...u, subscriptionTier: newTier, subscription_tier: newTier } : u));
    };

    const updateUser = async (id, updates) => {
        const { error } = await supabase.from('people').update(updates).eq('id', id);
        if (error) console.error("Error updating user:", error);

        setUsers(prev => prev.map(u => u.id === id ? { ...u, ...updates } : u));
    };

    return { users, addUser, removeUser, updateUserTier, updateUser };
}

import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const defaultSettings = {
    heroTitle: "Ready to cook, Chef?",
    siteName: "CWC+ Smart Hub",
    maintenanceMode: false,
    bannerEnabled: false,
    bannerText: "New Masterclass dropping this Friday! ≡ƒÜÇ",
    premiumTiers: [
        { id: 'tier1', name: 'Basic Premium', price: '5.99', benefits: 'Ad-free experience, 10 Recipes/mo' },
        { id: 'tier2', name: 'Pro Premium', price: '12.99', benefits: 'All Recipes, 1 Masterclass/mo, Priority Support' },
        { id: 'tier3', name: 'Elite Premium', price: '29.99', benefits: 'All Access, Live Q&A, VIP Community' }
    ],
    plugins: { stripe: false, mailchimp: false, zapier: false },
    apiKeys: [],
    volumePrices: {
        "Volume 1": "9.99",
        "Volume 2": "14.99"
    }
};

export function useAppSettings() {
    const [settings, setSettings] = useState(defaultSettings);

    useEffect(() => {
        const fetchSettings = async () => {
            const { data, error } = await supabase.from('settings').select('config').eq('id', 'platform').single();

            if (error) {
                console.error("Error fetching settings:", error);
                const stored = localStorage.getItem('cwc_settings');
                if (stored) setSettings(JSON.parse(stored));
                else setSettings(defaultSettings);
                return;
            }

            if (data && data.config) {
                setSettings({ ...defaultSettings, ...data.config });
            }
        };

        fetchSettings();

        const channel = supabase.channel('settings_changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'settings', filter: 'id=eq.platform' }, payload => {
                fetchSettings();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, []);

    const updateSettings = async (newSettings) => {
        const updated = { ...settings, ...newSettings };
        setSettings(updated);

        const { error } = await supabase.from('settings').upsert({ id: 'platform', config: updated, updated_at: new Date() });
        if (error) {
            console.error("Error updating settings:", error);
            // Fallback to local
            localStorage.setItem('cwc_settings', JSON.stringify(updated));
        }
    };

    return { settings, updateSettings };
}

