import { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { recipesData as initialRecipes } from '../data/recipes';

export function useRecipes() {
    const [recipes, setRecipes] = useState([]);

    useEffect(() => {
        const fetchRecipes = async () => {
            const { data, error } = await supabase.from('recipes').select('*').order('created_at', { ascending: false });

            if (error) {
                console.error("Error fetching recipes:", error);
                // Fallback to local
                const stored = localStorage.getItem('cwc_recipes');
                if (stored) setRecipes(JSON.parse(stored));
                else setRecipes(initialRecipes);
                return;
            }

            if (data && data.length > 0) {
                setRecipes(data);
            } else {
                // If table is empty, use initial static recipes (or we could seed them)
                setRecipes(initialRecipes);
            }
        };

        fetchRecipes();

        // Optional: Subscribe to changes
        const channel = supabase.channel('recipes_changes')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'recipes' }, payload => {
                fetchRecipes();
            })
            .subscribe();

        return () => supabase.removeChannel(channel);
    }, []);

    const addRecipe = async (newRecipe) => {
        const { data, error } = await supabase.from('recipes').insert([newRecipe]).select();
        if (error) {
            console.error("Error adding recipe:", error);
            // fallback
            const updated = [...recipes, { ...newRecipe, id: Date.now() }];
            setRecipes(updated);
        } else if (data) {
            // Realtime will update it, but optimistic update:
            setRecipes(prev => [data[0], ...prev.filter(r => r.id !== data[0].id)]);
        }
    };

    const updateRecipe = async (id, updatedRecipe) => {
        const { error } = await supabase.from('recipes').update(updatedRecipe).eq('id', id);
        if (error) console.error("Error updating recipe:", error);

        setRecipes(prev => prev.map(r => r.id === id ? { ...r, ...updatedRecipe } : r));
    };

    const deleteRecipe = async (id) => {
        const { error } = await supabase.from('recipes').delete().eq('id', id);
        if (error) console.error("Error deleting recipe:", error);

        setRecipes(prev => prev.filter(r => r.id !== id));
    };

    const publicRecipes = recipes.filter(r => r.status !== 'draft');

    return { recipes, publicRecipes, addRecipe, updateRecipe, deleteRecipe };
}

