import { useState, useEffect } from 'react';

const defaultUser = {
    name: "John Doe",
    subscriptionTier: "Free", // 'Free' or 'Premium'
    unlockedVolumes: [], // e.g. ['Volume 1', 'Summer Collection']
    unlockedClasses: [] // Array of class IDs
};

export function useUser() {
    const [user, setUser] = useState(defaultUser);

    useEffect(() => {
        const stored = localStorage.getItem('cwc_user');
        if (stored) {
            // Merge with defaultUser so any missing fields (old data) are filled in safely
            const parsed = JSON.parse(stored);
            setUser({ ...defaultUser, ...parsed });
        } else {
            localStorage.setItem('cwc_user', JSON.stringify(defaultUser));
        }
    }, []);

    const updateUser = (updates) => {
        const updatedUser = { ...user, ...updates };
        setUser(updatedUser);
        localStorage.setItem('cwc_user', JSON.stringify(updatedUser));
    };

    const unlockVolume = (volumeName) => {
        if (!user.unlockedVolumes.includes(volumeName)) {
            updateUser({ unlockedVolumes: [...user.unlockedVolumes, volumeName] });
        }
    };

    const unlockClass = (classId) => {
        if (!user.unlockedClasses.includes(classId)) {
            updateUser({ unlockedClasses: [...user.unlockedClasses, classId] });
        }
    };

    const hasAccessToVolume = (volumeName) => {
        if (!volumeName || volumeName === 'CWC Original') return true; // Free default volume
        if (user.subscriptionTier !== 'Free') return true;
        return user.unlockedVolumes.includes(volumeName);
    };

    const hasAccessToClass = (classId) => {
        if (user.subscriptionTier !== 'Free') return true;
        return user.unlockedClasses.includes(classId);
    };

    return { user, updateUser, unlockVolume, unlockClass, hasAccessToVolume, hasAccessToClass };
}

