  const [isCreating, setIsCreating] = useState(false);
  const [recipeForm, setRecipeForm] = useState({ title: '', author: '', time: '', image: '', category: 'Mains', difficulty: 'Beginner', baseServings: 2, ingredients: [{name: '', amount: ''}], steps: [''], status: 'published', isFeatured: false, tierRequired: 'Free' });
  const [classForm, setClassForm] = useState({ title: '', instructor: '', duration: '', price: '15.00', image: '', video: '', status: 'published', tierRequired: 'Plus', ingredients: [{name: '', amount: ''}], steps: [''] });
  const [personForm, setPersonForm] = useState({ name: '', email: '', subscriptionTier: 'Free' });
  const [rawText, setRawText] = useState("");
  const [deleteContext, setDeleteContext] = useState({ isOpen: false, coll: '', id: '', title: '' });

  const showToast = (message, type = 'success') => { setToast({ message, type }); setTimeout(() => setToast(null), 3000); };

  useEffect(() => {
    const initAuth = async () => {
      try {
        if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) await signInWithCustomToken(auth, __initial_auth_token);
        else await signInAnonymously(auth);
      } catch (err) { console.error(err); }
    };
    initAuth();
    const unsub = onAuthStateChanged(auth, setUser);
    return () => unsub();
  }, []);

  useEffect(() => {
    if (!user) return;
    const sRef = doc(db, 'artifacts', appId, 'public', 'data', 'settings', 'config');
    const uS = onSnapshot(sRef, (d) => { if (d.exists()) setSettings(prev => ({ ...prev, ...d.data() })); setLoading(false); }, () => setLoading(false));
    const rRef = collection(db, 'artifacts', appId, 'public', 'data', 'recipes');
    const uR = onSnapshot(rRef, (s) => setRecipes(s.docs.map(d => ({ id: d.id, ...d.data() }))));
    const cRef = collection(db, 'artifacts', appId, 'public', 'data', 'classes');
    const uC = onSnapshot(cRef, (s) => setClasses(s.docs.map(d => ({ id: d.id, ...d.data() }))));
    const pRef = collection(db, 'artifacts', appId, 'public', 'data', 'people');
    const uP = onSnapshot(pRef, (s) => setPeople(s.docs.map(d => ({ id: d.id, ...d.data() }))));
    return () => { uS(); uR(); uC(); uP(); };
  }, [user]);

  const handleSeedDemoData = async () => {
    if (!user) return;
    try {
      const pRef = collection(db, 'artifacts', appId, 'public', 'data', 'people');
      const rRef = collection(db, 'artifacts', appId, 'public', 'data', 'recipes');
      const cRef = collection(db, 'artifacts', appId, 'public', 'data', 'classes');

      for (const u of [
        { name: 'Kid Chef Timmy', email: 'timmy@kid.com', subscriptionTier: 'Free', createdAt: Date.now() },
        { name: 'Momma Bear', email: 'mom@home.com', subscriptionTier: 'Premium', createdAt: Date.now() }
      ]) await addDoc(pRef, u);

      await addDoc(rRef, {
        title: 'Magic Rainbow Pancakes', author: 'Chef Sparkles', time: '15 mins', category: 'Breakfast', difficulty: 'Beginner', 
        image: 'https://images.unsplash.com/photo-1575853121743-60c24f0a7502?q=80&w=1000&auto=format', 
        tierRequired: 'Free', isFeatured: true, status: 'published', baseServings: 4,
        ingredients: [{name: 'Pancake Mix', amount: '2 cups'}, {name: 'Food Coloring', amount: '3 drops'}], 
        steps: ['Mix the batter!', 'Add the magical colors!', 'Cook until fluffy!'], createdAt: Date.now()
      });

      await addDoc(cRef, {
        title: 'The Ultimate Cookie Masterclass', instructor: 'Grandma Betty', duration: '30m', price: '9.99', 
        image: 'https://images.unsplash.com/photo-1499636136210-6f4ee915583e?q=80&w=1000&auto=format', 
        video: 'https://www.youtube.com/embed/dQw4w9WgXcQ', tierRequired: 'Basic', status: 'published',
        ingredients: [{name: 'All-Purpose Flour', amount: '2 1/4 cups'}, {name: 'Chocolate Chips', amount: '2 cups'}, {name: 'Butter', amount: '1 cup'}],
        steps: ['Cream the butter and sugar until light and fluffy.', 'Mix in the dry ingredients.', 'Fold in chocolate chips.', 'Bake at 375┬░F for 10-12 minutes.'],
        createdAt: Date.now()
      });

      showToast("Magic Demo Data Created! ≡ƒÄë");
    } catch (e) { showToast("Oops! Magic failed.", 'error'); }
  };

  const handleSaveSettings = async () => {
    if (!user) return;
    try { await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'settings', 'config'), settings); showToast("Settings Saved Successfully! ≡ƒÜÇ"); } 
    catch (e) { showToast("Save failed", 'error'); }
  };

  const generateApiKey = async () => {
    if (!user) return;
    const newKey = { id: crypto.randomUUID(), key: `cwc_live_${crypto.randomUUID().replace(/-/g, '')}`, createdAt: Date.now(), name: 'New API Key' };
    const newSettings = { ...settings, apiKeys: [...(settings.apiKeys || []), newKey] };
    setSettings(newSettings);
    await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'settings', 'config'), newSettings);
    showToast("API Key Generated! ≡ƒöæ");
  };

  const removeApiKey = async (id) => {
    const newSettings = { ...settings, apiKeys: settings.apiKeys.filter(k => k.id !== id) };
    setSettings(newSettings);
    await setDoc(doc(db, 'artifacts', appId, 'public', 'data', 'settings', 'config'), newSettings);
    showToast("API Key Revoked ≡ƒùæ∩╕Å");
  };

  const handlePostRecipe = async (e) => {
    e.preventDefault();
    if (!user) return;
    try {
      const cleanIngredients = recipeForm.ingredients.filter(i => i.name.trim() !== '');
      const cleanSteps = recipeForm.steps.filter(s => s.trim() !== '');
      const { id, ...dataToSave } = recipeForm;
      const data = { ...dataToSave, ingredients: cleanIngredients, steps: cleanSteps, updatedAt: Date.now() };
      const rRef = collection(db, 'artifacts', appId, 'public', 'data', 'recipes');
      if (id) await updateDoc(doc(rRef, id), data); else await addDoc(rRef, { ...data, createdAt: Date.now() });
      setIsCreating(false);
      showToast("Recipe Published to the World! ≡ƒîì");
    } catch (e) { showToast("Save failed", 'error'); }
  };

  const handleSmartParse = () => {
    if (!rawText) return;
    const lines = rawText.split('\n').map(l => l.trim()).filter(Boolean);
    let title = lines[0] || "My Magic Recipe";
    let ingredients = []; let steps = []; let current = 'title';
    lines.forEach(line => {
      const l = line.toLowerCase();
      if (l.includes('ingredient') || l.includes('need') || l.includes('bahan')) current = 'ing';
      else if (l.includes('step') || l.includes('make it') || l.includes('how to') || l.includes('cara')) current = 'step';
      else if (current === 'ing') ingredients.push({ name: line, amount: '1' });
      else if (current === 'step') steps.push(line.replace(/^\d+\.?\s*/, ''));
    });
    setRecipeForm(prev => ({ ...prev, title, ingredients: ingredients.length ? ingredients : prev.ingredients, steps: steps.length ? steps : prev.steps }));
    setRawText("");
    showToast("Magic Applied! Γ£¿ Text converted to Recipe.");
  };

  const handleClassSmartParse = () => {
    if (!rawText) return;
    const lines = rawText.split('\n').map(l => l.trim()).filter(Boolean);
    let ingredients = []; let steps = []; let current = 'none';
    lines.forEach(line => {
      const l = line.toLowerCase();
      if (l.includes('ingredient') || l.includes('need') || l.includes('bahan')) current = 'ing';
      else if (l.includes('step') || l.includes('make it') || l.includes('how to') || l.includes('cara')) current = 'step';
      else if (current === 'ing') ingredients.push({ name: line, amount: '1' });
      else if (current === 'step') steps.push(line.replace(/^\d+\.?\s*/, ''));
    });
    setClassForm(prev => ({ ...prev, ingredients: ingredients.length ? ingredients : prev.ingredients, steps: steps.length ? steps : prev.steps }));
    setRawText("");
    showToast("Magic Applied! Γ£¿ Class Recipe auto-filled.");
  };

  const requestDelete = (coll, id, title) => setDeleteContext({ isOpen: true, coll, id, title });
  const executeDelete = async () => {
    if (!user) return;
    try { await deleteDoc(doc(db, 'artifacts', appId, 'public', 'data', deleteContext.coll, deleteContext.id)); showToast("Deleted forever! ≡ƒùæ∩╕Å"); } 
    catch (e) { showToast("Delete failed", 'error'); } finally { setDeleteContext({ isOpen: false, coll: '', id: '', title: '' }); }
  };

  const fRecipes = useMemo(() => recipes.filter(r => r.title.toLowerCase().includes(searchQuery.toLowerCase())), [recipes, searchQuery]);
  const fPeople = useMemo(() => people.filter(p => (p.name || '').toLowerCase().includes(searchQuery.toLowerCase())), [people, searchQuery]);
  const fClasses = useMemo(() => classes.filter(c => c.title.toLowerCase().includes(searchQuery.toLowerCase())), [classes, searchQuery]);
  const mrr = useMemo(() => people.reduce((acc, p) => acc + parseFloat(settings.tierPrices[p.subscriptionTier] || 0), 0), [people, settings]);

  if (loading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center"><Loader2 className="w-16 h-16 text-indigo-500 animate-spin" /></div>;

  const NavItem = ({ id, label, icon: Icon }) => (
    <button onClick={() => { setActiveTab(id); setIsMobileOpen(false); }} className={`w-full flex items-center gap-4 px-6 py-5 rounded-full text-lg font-black transition-all ${activeTab === id ? 'bg-indigo-600 text-white shadow-[0_10px_30px_rgba(79,70,229,0.4)] scale-105' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
      <Icon size={24} className={activeTab === id ? 'text-white' : 'text-slate-500'} /> {label}
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-950 text-white flex overflow-hidden font-sans selection:bg-indigo-500/30">
      <AnimatePresence>{toast && <Toast {...toast} onClose={() => setToast(null)} />}</AnimatePresence>
      <ConfirmModal {...deleteContext} onConfirm={executeDelete} onCancel={() => setDeleteContext({ ...deleteContext, isOpen: false })} />

      {/* Sidebar */}
      <div className={`fixed inset-y-0 left-0 z-50 w-80 bg-slate-900 border-r border-slate-800 flex flex-col transition-transform duration-300 ${isMobileOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0 lg:static'}`}>
        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg"><ChefHat size={28} color="white"/></div>
             <h1 className="text-2xl font-black text-white tracking-tight">CWC<span className="text-indigo-500">+</span> CMS</h1>
          </div>
          <button onClick={() => setIsMobileOpen(false)} className="lg:hidden p-2 text-slate-400"><X size={24} /></button>
        </div>
        <nav className="flex-1 px-4 space-y-2 overflow-y-auto">
          <NavItem id="dashboard" label="Home Base" icon={LayoutDashboard} />
          <NavItem id="recipes" label="Meals & Recipes" icon={ChefHat} />
          <NavItem id="classes" label="Video Library" icon={Video} />
          <NavItem id="people" label="Members" icon={Users} />
          <NavItem id="plugins" label="Plugins & APIs" icon={Puzzle} />
          <NavItem id="settings" label="Settings" icon={Settings} />
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto relative">
        <header className="sticky top-0 z-40 bg-slate-950/80 backdrop-blur-3xl border-b border-slate-800 p-4 lg:p-8 flex justify-between items-center">
          <div className="flex items-center gap-4 flex-1 max-w-3xl">
            <button onClick={() => setIsMobileOpen(true)} className="lg:hidden p-3 bg-slate-800 rounded-2xl"><Menu size={24} /></button>
            <div className="relative flex-1">
              <Search size={24} className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500" />
              <input type="text" placeholder={`Search ${activeTab}...`} value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-slate-900 border-2 border-slate-800 focus:border-indigo-500 rounded-full pl-16 pr-6 py-4 text-lg font-bold outline-none transition-all placeholder:text-slate-500" />
            </div>
          </div>
          <div className="hidden lg:flex items-center gap-4">
             <div className="px-6 py-3 bg-emerald-500/10 border-2 border-emerald-500/20 rounded-full flex items-center gap-3">
                <div className="w-3 h-3 bg-emerald-500 rounded-full animate-ping" />
                <span className="text-sm font-black text-emerald-400 uppercase tracking-widest">System Online</span>
             </div>
             <button onClick={handleSeedDemoData} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-full font-black text-sm flex items-center gap-2 shadow-lg hover:scale-105 transition-all"><Wand2 size={18} /> Make Magic Demo</button>
          </div>
        </header>

        <main className="p-4 lg:p-10 w-full max-w-7xl mx-auto pb-40">
          
          {/* DASHBOARD */}
          {activeTab === 'dashboard' && (
            <div className="space-y-10">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                  { label: 'Total Recipes', val: recipes.length, icon: ChefHat, bg: 'bg-indigo-500', trend: 'Growing!' },
                  { label: 'Masterclasses', val: classes.length, icon: Video, bg: 'bg-rose-500', trend: 'Watch now' },
                  { label: 'Happy Members', val: people.length, icon: Users, bg: 'bg-emerald-500', trend: 'Joining fast' },
                  { label: 'Monthly Revenue', val: '$' + mrr.toFixed(0), icon: DollarSign, bg: 'bg-amber-500', trend: 'Real money!' },
                ].map((stat, i) => (
                  <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }} key={stat.label} className="p-8 rounded-[40px] bg-slate-900 border-2 border-slate-800 flex flex-col items-center text-center group hover:border-slate-700 transition-colors">
                    <div className={`w-20 h-20 ${stat.bg} rounded-full flex items-center justify-center mb-6 shadow-xl shadow-${stat.bg.split('-')[1]}-500/20 group-hover:scale-110 transition-transform`}><stat.icon size={36} className="text-white" /></div>
                    <h3 className="text-5xl font-black text-white mb-2">{stat.val}</h3>
                    <p className="text-slate-400 text-sm font-black uppercase tracking-widest">{stat.label}</p>
                    <div className="mt-4 px-4 py-2 bg-slate-800 rounded-full text-xs font-bold text-slate-300">{stat.trend}</div>
                  </motion.div>
                ))}
              </div>

              <div className="p-10 rounded-[40px] bg-indigo-600 relative overflow-hidden flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl shadow-indigo-600/20">
                 <Wand2 className="absolute -right-10 -bottom-10 w-64 h-64 text-white opacity-10" />
                 <div className="relative z-10 text-center md:text-left">
                    <h2 className="text-4xl font-black text-white mb-4">Want to test the magic?</h2>
                    <p className="text-xl text-indigo-100 font-medium">Click the button to automatically fill your platform with fake users, delicious recipes, and cool videos to see how it looks!</p>
                 </div>
                 <button onClick={handleSeedDemoData} className="relative z-10 px-10 py-6 bg-white text-indigo-600 rounded-full font-black text-2xl hover:scale-105 active:scale-95 transition-all shadow-xl whitespace-nowrap">
                    Add Magic Data Γ£¿
                 </button>
              </div>
            </div>
          )}

          {/* RECIPES */}
          {activeTab === 'recipes' && (
            <div>
              <div className="flex flex-col sm:flex-row justify-between items-center gap-6 mb-10">
                <h3 className="text-5xl font-black">All Recipes</h3>
                {!isCreating && <button onClick={() => { setRecipeForm({ title: '', author: '', time: '', image: '', category: 'Mains', difficulty: 'Beginner', baseServings: 2, ingredients: [{name: '', amount: ''}], steps: [''], status: 'published', isFeatured: false, tierRequired: 'Free' }); setIsCreating(true); }} className="px-10 py-5 bg-indigo-600 rounded-full font-black text-xl shadow-xl flex items-center gap-3 hover:scale-105 active:scale-95 transition-all"><Plus size={24} /> Create a Recipe</button>}
              </div>

              {!isCreating ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {fRecipes.map(r => (
                    <motion.div layout key={r.id} className="bg-slate-900 border-2 border-slate-800 rounded-[40px] overflow-hidden group hover:border-indigo-500/50 transition-colors">
                      <div className="h-64 relative">
                        {r.image ? <img src={r.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" /> : <div className="w-full h-full bg-slate-800 flex items-center justify-center"><ChefHat size={48} className="text-slate-600"/></div>}
                        <div className="absolute inset-0 bg-slate-950/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-sm">
                           <button onClick={() => { setRecipeForm(r); setIsCreating(true); }} className="w-16 h-16 bg-white text-slate-900 rounded-full flex items-center justify-center hover:scale-110 transition-transform shadow-xl"><Edit3 size={28}/></button>
                           <button onClick={() => requestDelete('recipes', r.id, r.title)} className="w-16 h-16 bg-rose-500 text-white rounded-full flex items-center justify-center hover:scale-110 transition-transform shadow-xl"><Trash2 size={28}/></button>
                        </div>
                        <div className={`absolute top-4 left-4 px-4 py-2 rounded-full text-xs font-black uppercase tracking-widest backdrop-blur-md border ${TIER_META[r.tierRequired]?.bg} ${TIER_META[r.tierRequired]?.color} ${TIER_META[r.tierRequired]?.border}`}>{TIER_META[r.tierRequired]?.label}</div>
                        {r.isFeatured && <div className="absolute top-4 right-4 w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center shadow-lg"><Star size={20} className="text-white fill-white" /></div>}
                      </div>
                      <div className="p-8">
                        <h4 className="font-black text-2xl mb-2 text-white">{r.title}</h4>
                        <div className="flex flex-wrap gap-2 mb-6">
                           <span className="px-3 py-1.5 bg-slate-800 rounded-lg text-xs font-bold text-slate-300">{r.category}</span>
                           <span className="px-3 py-1.5 bg-slate-800 rounded-lg text-xs font-bold text-slate-300">{r.difficulty}</span>
                        </div>
                        <div className="flex items-center justify-between text-slate-500 text-sm font-black uppercase">
                           <span className="flex items-center gap-2"><Clock size={16}/> {r.time}</span>
                           <span className="flex items-center gap-2"><Flame size={16}/> {r.ingredients?.length || 0} parts</span>
                        </div>
                      </div>
                    </motion.div>
                  ))}
                  {fRecipes.length === 0 && (
                    <div className="col-span-full py-40 text-center bg-slate-900 rounded-[40px] border-4 border-dashed border-slate-800">
                      <ChefHat size={80} className="mx-auto text-slate-700 mb-8" />
                      <h4 className="text-3xl font-black text-slate-400 mb-4">No Recipes Here!</h4>
                      <button onClick={() => setIsCreating(true)} className="px-8 py-4 bg-slate-800 text-white rounded-full font-black text-lg hover:bg-slate-700">Add One Now</button>
                    </div>
                  )}
                </div>
              ) : (
                <div className="max-w-4xl mx-auto bg-slate-900 border-2 border-slate-800 rounded-[40px] overflow-hidden shadow-2xl">
                   <div className="bg-indigo-600 p-10 flex justify-between items-center relative overflow-hidden">
                      <Wand2 className="absolute right-10 opacity-20 w-40 h-40" />
                      <h4 className="text-4xl font-black text-white relative z-10">{recipeForm.id ? 'Edit Recipe' : 'New Recipe Magic'}</h4>
                      <button onClick={() => setIsCreating(false)} className="w-14 h-14 bg-white/20 hover:bg-white/30 rounded-full flex items-center justify-center relative z-10 transition-colors"><X size={28}/></button>
                   </div>

                   <div className="p-10 space-y-10">
                      {/* Magic Parser Box */}
                      <div className="p-8 bg-indigo-500/10 border-2 border-indigo-500/30 rounded-[32px] text-center">
                          <Wand2 size={40} className="mx-auto text-indigo-400 mb-4" />
                          <h5 className="text-2xl font-black text-indigo-300 mb-2">Magic Auto-Fill!</h5>
                          <p className="text-slate-400 font-medium mb-6">Paste your recipe text here, and we'll figure out the ingredients and steps for you.</p>
                          <textarea rows={3} value={rawText} onChange={e => setRawText(e.target.value)} placeholder="Paste the whole recipe here..." className="w-full bg-slate-950 border-2 border-indigo-500/20 rounded-[24px] px-6 py-5 text-lg text-white placeholder:text-slate-600 focus:outline-none focus:border-indigo-500 mb-4" />
                          <button type="button" onClick={handleSmartParse} className="w-full py-5 bg-indigo-600 rounded-full font-black text-xl hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-500/20">Do The Magic Γ£¿</button>
                      </div>

                      <form onSubmit={handlePostRecipe} className="space-y-10">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-3">
                                <label className="text-sm font-black uppercase text-slate-500 ml-2">Name of the Dish</label>
                                <input required type="text" value={recipeForm.title} onChange={e => setRecipeForm({...recipeForm, title: e.target.value})} className="w-full bg-slate-950 border-2 border-slate-800 rounded-full px-6 py-5 text-xl font-bold focus:border-indigo-500 outline-none" placeholder="e.g. Magic Pancakes" />
                            </div>
                            <div className="space-y-3">
                                <label className="text-sm font-black uppercase text-slate-500 ml-2">Who Gets to See This?</label>
                                <select value={recipeForm.tierRequired} onChange={e => setRecipeForm({...recipeForm, tierRequired: e.target.value})} className="w-full bg-slate-950 border-2 border-slate-800 rounded-full px-6 py-5 text-xl font-bold focus:border-indigo-500 outline-none text-white cursor-pointer appearance-none">
                                    {Object.keys(TIER_META).map(t => <option key={t} value={t}>{t} Level & Up</option>)}
                                </select>
                            </div>
                            <div className="col-span-1 md:col-span-2 space-y-3">
                                <label className="text-sm font-black uppercase text-slate-500 ml-2">Picture Link (URL)</label>
                                <input type="text" value={recipeForm.image} onChange={e => setRecipeForm({...recipeForm, image: e.target.value})} className="w-full bg-slate-950 border-2 border-slate-800 rounded-full px-6 py-5 text-xl font-bold focus:border-indigo-500 outline-none" placeholder="https://..." />
                            </div>
                        </div>

                        {/* Visual Builders */}
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                            {/* Ingredients */}
                            <div className="bg-slate-950 p-6 rounded-[40px] border-2 border-slate-800">
                                <div className="flex items-center justify-between mb-6 px-2">
                                    <h5 className="font-black text-xl text-white">Ingredients</h5>
                                    <button type="button" onClick={() => setRecipeForm({...recipeForm, ingredients: [...(recipeForm.ingredients || []), {name: '', amount: ''}]})} className="w-10 h-10 bg-indigo-600 rounded-full flex items-center justify-center hover:bg-indigo-500"><Plus size={20}/></button>
                                </div>
                                <div className="space-y-3">
                                    {(recipeForm.ingredients || []).map((ing, idx) => (
                                        <div key={idx} className="flex gap-2">
                                            <input placeholder="Qty (2 cups)" value={ing.amount} onChange={e => { const n = [...recipeForm.ingredients]; n[idx].amount = e.target.value; setRecipeForm({...recipeForm, ingredients: n}); }} className="w-1/3 bg-slate-900 border-2 border-slate-800 rounded-2xl px-4 py-4 text-sm font-bold outline-none focus:border-indigo-500" />
                                            <input placeholder="Item (Flour)" value={ing.name} onChange={e => { const n = [...recipeForm.ingredients]; n[idx].name = e.target.value; setRecipeForm({...recipeForm, ingredients: n}); }} className="w-2/3 bg-slate-900 border-2 border-slate-800 rounded-2xl px-4 py-4 text-sm font-bold outline-none focus:border-indigo-500" />
