                    <div>
                        <h3 className="text-5xl font-black mb-2">Settings</h3>
                        <p className="text-xl text-slate-400 font-medium">Control the core of your app.</p>
                    </div>
                    <button onClick={handleSaveSettings} className="px-10 py-5 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-full shadow-xl shadow-indigo-600/20 flex items-center gap-3 text-xl active:scale-95 transition-all">
                        <Save size={24}/> Save Changes
                    </button>
                </div>

                <div className="space-y-8">
                    {/* Big Pricing Cards */}
                    <div className="p-10 rounded-[40px] bg-slate-900 border-2 border-slate-800 space-y-8">
                        <h4 className="font-black text-2xl uppercase tracking-widest text-slate-500 flex items-center gap-3"><DollarSign size={28} className="text-emerald-400"/> Monthly Prices</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                            {Object.keys(settings.tierPrices).map(tier => (
                                <div key={tier} className={`p-8 rounded-[32px] border-4 ${TIER_META[tier].bg} ${TIER_META[tier].border}`}>
                                    <label className={`text-xl font-black uppercase tracking-widest ${TIER_META[tier].color} mb-4 block`}>{tier}</label>
                                    <div className="relative">
                                        <span className="absolute left-0 top-1/2 -translate-y-1/2 text-4xl text-slate-600 font-black">$</span>
                                        <input type="number" step="0.01" value={settings.tierPrices[tier]} onChange={e => setSettings({...settings, tierPrices: {...settings.tierPrices, [tier]: e.target.value}})} className="w-full bg-transparent border-none pl-8 text-5xl font-black text-white focus:outline-none" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Site Basics */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="p-10 rounded-[40px] bg-slate-900 border-2 border-slate-800 space-y-8">
                            <h4 className="font-black text-2xl uppercase tracking-widest text-slate-500 flex items-center gap-3"><Palette size={28} className="text-indigo-400"/> The Basics</h4>
                            <div className="space-y-6">
                                <div>
                                    <label className="text-sm font-black uppercase text-slate-500 block mb-3 ml-2">Name of your site</label>
                                    <input type="text" value={settings.siteName} onChange={e => setSettings({...settings, siteName: e.target.value})} className="w-full bg-slate-950 border-2 border-slate-800 rounded-full px-6 py-5 text-lg font-bold outline-none focus:border-indigo-500" />
                                </div>
                                <div className="p-6 bg-rose-500/10 border-2 border-rose-500/20 rounded-[32px] flex items-center justify-between">
                                    <div>
                                        <p className="text-lg font-black text-rose-400">Lock the site?</p>
                                        <p className="text-xs text-rose-400/60 font-bold uppercase mt-1">Maintenance mode</p>
                                    </div>
                                    <button onClick={() => setSettings({...settings, maintenanceMode: !settings.maintenanceMode})} className={`w-16 h-8 rounded-full relative transition-colors border-2 ${settings.maintenanceMode ? 'bg-rose-500 border-rose-500' : 'bg-slate-950 border-slate-700'}`}>
                                        <motion.div animate={{ x: settings.maintenanceMode ? 32 : 2 }} className="w-6 h-6 bg-white rounded-full absolute top-0.5" />
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Top Banner */}
                        <div className="p-10 rounded-[40px] bg-slate-900 border-2 border-slate-800 space-y-8">
                            <h4 className="font-black text-2xl uppercase tracking-widest text-slate-500 flex items-center gap-3"><Megaphone size={28} className="text-amber-400"/> Top Banner</h4>
                            <div className="space-y-6">
                                <div className="flex items-center justify-between">
                                    <p className="text-lg font-black text-white">Turn banner ON</p>
                                    <button onClick={() => setSettings({...settings, bannerEnabled: !settings.bannerEnabled})} className={`w-16 h-8 rounded-full relative transition-colors border-2 ${settings.bannerEnabled ? 'bg-amber-500 border-amber-500' : 'bg-slate-950 border-slate-700'}`}>
                                        <motion.div animate={{ x: settings.bannerEnabled ? 32 : 2 }} className="w-6 h-6 bg-white rounded-full absolute top-0.5" />
                                    </button>
                                </div>
                                <textarea rows={4} value={settings.bannerText} onChange={e => setSettings({...settings, bannerText: e.target.value})} className="w-full bg-slate-950 border-2 border-slate-800 rounded-[32px] px-6 py-5 text-lg font-bold outline-none focus:border-indigo-500" placeholder="Type your announcement here..." />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}
